// ==========================================
// Router: QR or Product Image
// ==========================================

const output = $input.first().json.output || '';
const trimmed = output.trim();

// 1. ตรวจสอบว่าเป็น QR Code
if (trimmed === 'QR') {
  return [
    {
      json: {
        type: 'qr',
        senderId: $('Extract Event2').first().json.senderId,
        pageId: $('Extract Event2').first().json.pageId
      }
    }
  ];
}

// 2. ตรวจสอบว่าเป็นรูปสินค้า (เช็คว่าขึ้นต้นด้วย IMAGE|)
// โครงสร้าง input ต้องเป็น: IMAGE|URL|ข้อความ
if (trimmed.startsWith('IMAGE|')) {

  // สั่งผ่าข้อความด้วยตัว |
  const parts = trimmed.split('|'); 

  // parts[0] = "IMAGE"
  // parts[1] = URL
  // parts[2] = ข้อความ (Caption)
  const imageUrl = parts[1] ? parts[1].trim() : '';
  const captionText = parts[2] ? parts[2].trim() : '';

  // เช็คว่ามี URL และเป็น https ไหม
  if (imageUrl && imageUrl.startsWith('https')) {
    return [
      {
        json: {
          type: 'product_image',
          imageUrl: imageUrl,
          caption: captionText, // ส่งข้อความไปด้วย (เผื่อใช้)
          senderId: $('Extract Event2').first().json.senderId,
          pageId: $('Extract Event2').first().json.pageId
        }
      }
    ];
  }
}

// 3. ถ้าไม่ใช่ทั้ง QR และรูปภาพ = ส่งเป็นข้อความปกติ (Empty Array เพื่อให้ Workflow ไปเส้นทางอื่น หรือจบ process)
return [];

