// ==========================================
// Safe AI Response Handler
// ป้องกัน Error จาก Empty Message + ตรวจจับ ADMIN_ALERT
// ==========================================

const items = $input.all();

// ดึงข้อมูลจาก AI Agent
const aiResponse = items[0].json;

// ลองดึง output จากหลายแหล่ง
let message = aiResponse.output 
           || aiResponse.text 
           || aiResponse.response 
           || aiResponse.message
           || '';

// ทำความสะอาดข้อความ
message = String(message).trim();

console.log('=== AI OUTPUT ===');
console.log(message);
console.log('=================');

// ตรวจสอบว่าเป็น ADMIN_ALERT หรือไม่
if (message.startsWith('🚨Admin Alert')) {
  // แยกชื่อ Facebook ออกมา
  const customerName = message.replace('🚨Admin Alert', '').replace('ต้องการความช่วยเหลือ', '').trim();

  console.log('🚨 ADMIN ALERT DETECTED!');
  console.log('Customer:', customerName);

  // ไม่ส่งข้อความให้ลูกค้า เพียงแค่แจ้ง Telegram
  // ส่ง flag ว่าเป็น Admin Alert แต่ไม่มี message
  return [{
    json: {
      senderId: $('Extract Event2').first().json.senderId,
      pageId: $('Extract Event2').first().json.pageId,
      message: '', // ไม่ส่งข้อความใดๆ
      isAdminAlert: true,
      customerName: customerName,
      senderFullName: $('Extract Event2').first().json.senderFullName || customerName,
      skipSendMessage: true // flag เพื่อข้ามการส่งข้อความ
    }
  }];
}

// ตรวจสอบว่าข้อความว่างหรือไม่
if (!message || message === '') {
  // ส่งข้อความสำรอง
  return [{
    json: {
      senderId: $('Extract Event2').first().json.senderId,
      pageId: $('Extract Event2').first().json.pageId,
      message: 'ขอโทษครับ มีปัญหาเล็กน้อย กรุณาถามใหม่อีกครั้งนะครับ',
      isAdminAlert: false,
      skipSendMessage: false
    }
  }];
}

// ส่งข้อความปกติ
return [{
  json: {
    senderId: $('Extract Event2').first().json.senderId,
    pageId: $('Extract Event2').first().json.pageId,
    message: message,
    isAdminAlert: false,
    skipSendMessage: false
  }
}];

