// ==========================================
// Prepare Telegram Message - รองรับทั้ง Order Summary และ Admin Alert
// ==========================================

const filterResponse = $('Filter AI Response2').first().json;
const aiResponse = filterResponse.message || '';
const isAdminAlert = filterResponse.isAdminAlert || false;
const customerName = filterResponse.customerName || filterResponse.senderFullName || '';

// ดึง senderFullName จาก node ก่อนหน้า
const senderFullName = filterResponse.senderFullName || customerName;

console.log('=== PREPARE TELEGRAM ===');
console.log('Is Admin Alert:', isAdminAlert);
console.log('Customer Name:', customerName);
console.log('Sender Full Name:', senderFullName);
console.log('========================');

let telegramMessage = '';

// ถ้าเป็น Admin Alert
if (isAdminAlert) {
  telegramMessage = `🚨 Admin Alert\n${customerName} ต้องการความช่วยเหลือ`;
  console.log('📤 Sending Admin Alert to Telegram');
} 
// ถ้าเป็น Order Summary
else {
  // ดึงข้อมูลจากข้อความ AI
  const lines = aiResponse.split('\n');

  let orderDate = '';
  let facebookName = senderFullName;
  let customerInfo = {
    name: '',
    phone: '',
    address: ''
  };
  let orderItems = [];
  let totalAmount = '';
  let paymentMethod = 'ปลายทาง';

  // วิเคราะห์ข้อความเพื่อแยกข้อมูล
  let isInItemSection = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // ดึงวันที่
    if (line.startsWith('วันที่')) {
      orderDate = line.replace('วันที่ :', '').replace('วันที่:', '').trim();
    }

    // ดึงชื่อ Facebook
    if (line.includes('Facebook')) {
      const extracted = line.replace('Facebook', '').replace('ชื่อ', '').replace(':', '').trim();
      if (extracted) facebookName = extracted;
    }

    // ดึงข้อมูลลูกค้า
    if (line.startsWith('ชื่อ:')) {
      customerInfo.name = line.replace('ชื่อ:', '').trim();
    }

    if (line.startsWith('เบอร์:')) {
      customerInfo.phone = line.replace('เบอร์:', '').trim();
    }

    if (line.startsWith('ที่อยู่:')) {
      customerInfo.address = line.replace('ที่อยู่:', '').trim();
    }

    // ดึงรายการสินค้า
    if (line === 'รายการ:') {
      isInItemSection = true;
      continue;
    }

    if (isInItemSection && line.startsWith('-')) {
      orderItems.push(line);
    }

    if (line.includes('━━━━━━━━━━━━━') && isInItemSection) {
      isInItemSection = false;
    }

    // ดึงยอดรวม
    if (line.includes('รวม:')) {
      const match = line.match(/รวม:\s*(.+?)฿/);
      if (match) {
        totalAmount = match[1].trim();
      }
    }

    // ดึงรูปแบบการชำระเงิน
    if (line.includes('รูปแบบ:')) {
      const extracted = line.replace('รูปแบบ:', '').trim();
      if (extracted) {
        // แปลงเป็นรูปแบบที่ต้องการ
        if (extracted.toLowerCase().includes('โอน')) {
          paymentMethod = 'โอนเงิน';
        } else if (extracted.toLowerCase().includes('ปลายทาง') || extracted.toLowerCase().includes('cod')) {
          paymentMethod = 'ปลายทาง';
        } else {
          paymentMethod = extracted;
        }
      }
    }
  }

  // สร้างวันที่ปัจจุบัน
  const now = new Date();

  // ถ้าไม่มี orderDate ให้สร้างใหม่
  if (!orderDate) {
    const day = String(now.getDate()).padStart(2, '0');
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const year = now.getFullYear();
    orderDate = `${day}/${month}/${year}`;
  }

  // สร้างข้อความรายการสินค้า
  let itemsText = '';
  if (orderItems.length > 0) {
    itemsText = orderItems.join('\n');
  } else {
    itemsText = '- [ชื่อสินค้าจาก Sheet] [ขนาด] x [จำนวน] = [ราคาจาก Sheet]฿';
  }

  // สร้างข้อความสำหรับ Telegram (ตามรูปแบบใหม่)
  telegramMessage = `📦 ออเดอร์เข้าใหม่
วันที่ : ${orderDate}
รูปแบบ: ${paymentMethod}
ชื่อ Facebook: ${facebookName}
━━━━━━━━━━━━━
ชื่อ: ${customerInfo.name || '[ชื่อลูกค้า]'}
เบอร์: ${customerInfo.phone || '[เบอร์โทร]'}
ที่อยู่: ${customerInfo.address || '[ที่อยู่เต็ม]'}
━━━━━━━━━━━━━
รายการ:
${itemsText}
รวม: ${totalAmount || '[ยอดรวมจาก Sheet]'}฿`;

  console.log('📦 Sending Order Summary to Telegram');
}

// ส่ง data กลับไป
return {
  json: {
    telegramMessage: telegramMessage,
    rawData: aiResponse,
    isAdminAlert: isAdminAlert
  }
};

